import React, { useState, useEffect } from 'react';
import { getChannels, deleteChannel } from '../services/api';
import { Link } from 'react-router-dom';

const Channels = () => {
  const [channels, setChannels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    country: '',
    category: ''
  });

  const categories = [
    'Noticias', 'Entretenimiento', 'Deportes', 'Películas', 'Series',
    'Música', 'Infantil', 'Documentales', 'Religioso', 'Educativo',
    'Variedades', 'Internacional'
  ];

  const countries = [
    'España', 'México', 'Argentina', 'Colombia', 'Chile', 'Perú',
    'Venezuela', 'Ecuador', 'Estados Unidos', 'Internacional'
  ];

  useEffect(() => {
    loadChannels();
  }, [filters]);

  const loadChannels = async () => {
    try {
      setLoading(true);
      const data = await getChannels(filters);
      setChannels(data);
    } catch (error) {
      console.error('Error cargando canales:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id, name) => {
    if (window.confirm(`¿Eliminar canal "${name}"?`)) {
      try {
        await deleteChannel(id);
        setChannels(channels.filter(c => c.id !== id));
      } catch (error) {
        alert('Error eliminando canal');
      }
    }
  };

  const handleFilterChange = (e) => {
    setFilters({
      ...filters,
      [e.target.name]: e.target.value
    });
  };

  const clearFilters = () => {
    setFilters({ country: '', category: '' });
  };

  if (loading) return <div className="p-4 text-white">Cargando canales...</div>;

  return (
    <div className="p-6 bg-gray-900 min-h-screen text-white">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold">Canales de TV</h1>
        <Link
          to="/admin/add-channel"
          className="bg-red-600 hover:bg-red-700 px-4 py-2 rounded font-medium"
        >
          Agregar Canal
        </Link>
      </div>

      {/* Filtros */}
      <div className="mb-6 p-4 bg-gray-800 rounded-lg">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <select
            name="country"
            value={filters.country}
            onChange={handleFilterChange}
            className="p-2 bg-gray-700 border border-gray-600 rounded"
          >
            <option value="">Todos los países</option>
            {countries.map(country => (
              <option key={country} value={country}>{country}</option>
            ))}
          </select>

          <select
            name="category"
            value={filters.category}
            onChange={handleFilterChange}
            className="p-2 bg-gray-700 border border-gray-600 rounded"
          >
            <option value="">Todas las categorías</option>
            {categories.map(category => (
              <option key={category} value={category}>{category}</option>
            ))}
          </select>

          <button
            onClick={clearFilters}
            className="bg-gray-600 hover:bg-gray-500 px-4 py-2 rounded"
          >
            Limpiar Filtros
          </button>
        </div>
      </div>

      {/* Lista de Canales */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {channels.map(channel => (
          <div key={channel.id} className="bg-gray-800 rounded-lg p-4 hover:bg-gray-750 transition-colors">
            <div className="flex items-start justify-between mb-3">
              <div className="flex items-center space-x-3 flex-1">
                {channel.logo && (
                  <img
                    src={channel.logo}
                    alt={channel.name}
                    className="w-12 h-12 object-contain bg-white rounded"
                    onError={(e) => e.target.style.display = 'none'}
                  />
                )}
                <div className="flex-1 min-w-0">
                  <h3 className="font-semibold text-lg truncate">{channel.name}</h3>
                  <p className="text-sm text-gray-400">{channel.country}</p>
                </div>
              </div>
            </div>

            <div className="mb-3">
              <span className="inline-block bg-red-600 text-xs px-2 py-1 rounded">
                {channel.category}
              </span>
            </div>

            <div className="flex space-x-2">
              <Link
                to={`/player/channel/${channel.id}`}
                className="flex-1 bg-green-600 hover:bg-green-700 text-center py-2 rounded text-sm font-medium"
              >
                Ver Canal
              </Link>
              <button
                onClick={() => handleDelete(channel.id, channel.name)}
                className="bg-red-600 hover:bg-red-700 px-3 py-2 rounded text-sm"
              >
                🗑️
              </button>
            </div>

            <div className="mt-2 text-xs text-gray-500 truncate">
              {channel.stream_url}
            </div>
          </div>
        ))}
      </div>

      {channels.length === 0 && (
        <div className="text-center py-12">
          <p className="text-gray-400 text-lg mb-4">No hay canales disponibles</p>
          <Link
            to="/admin/add-channel"
            className="bg-red-600 hover:bg-red-700 px-6 py-3 rounded font-medium"
          >
            Agregar Primer Canal
          </Link>
        </div>
      )}

      <div className="mt-6 text-center text-gray-400">
        Total: {channels.length} canales
      </div>
    </div>
  );
};

export default Channels;
